create extension if not exists pgcrypto;
create table profiles (id uuid primary key references auth.users(id), full_name text, role text check (role in ('ADMIN','MANAGER','SALES','PURCHASE','LOGISTICS','VIEWER')), department text, created_at timestamptz default now(), updated_at timestamptz default now());
create table customers (id uuid primary key default gen_random_uuid(), customer_name text not null, customer_code text, city text, state text, country text, sales_person text, created_at timestamptz default now(), updated_at timestamptz default now());
create table suppliers (id uuid primary key default gen_random_uuid(), supplier_name text not null, supplier_code text, country text, contact_person text, email text, phone text, created_at timestamptz default now(), updated_at timestamptz default now());
create table shipments (id uuid primary key default gen_random_uuid(), shipment_no text unique not null, shipment_direction text not null check (shipment_direction in ('IMPORT','EXPORT')), shipment_type text, reference_no text, customer_id uuid references customers(id), supplier_id uuid references suppliers(id), customer_name text, supplier_name text, sales_person text, purchase_person text, carrier text, forwarder text, cha text, bl_no text, booking_no text, pol text, pod text, origin_country text, destination_country text, incoterms text, payment_terms text, current_status text default 'OPEN', current_milestone text, eta date, previous_eta date, etd date, vessel text, voyage text, last_event text, last_location text, source text, confidence integer default 0, review_status text default 'OK', risk_status text default 'NORMAL', created_by uuid references auth.users(id), created_at timestamptz default now(), updated_at timestamptz default now(), last_checked_at timestamptz, closed_at timestamptz, error text);
create table containers (id uuid primary key default gen_random_uuid(), shipment_id uuid references shipments(id) on delete cascade, container_no text not null, container_type text, seal_no text, gross_weight numeric, net_weight numeric, packages integer, current_status text, current_location text, eta date, last_event text, last_checked_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now());
create table shipment_milestones (id uuid primary key default gen_random_uuid(), shipment_id uuid references shipments(id) on delete cascade, milestone_name text not null, milestone_type text, planned_date date, actual_date date, status text default 'PENDING', delay_days integer default 0, owner_name text, remarks text, created_at timestamptz default now(), updated_at timestamptz default now());
create table documents (id uuid primary key default gen_random_uuid(), shipment_id uuid references shipments(id) on delete cascade, document_type text not null, document_no text, document_date date, received_date date, sent_date date, status text default 'PENDING', file_path text, file_url text, remarks text, created_at timestamptz default now(), updated_at timestamptz default now());
create table carrier_rules (id uuid primary key default gen_random_uuid(), carrier text not null, active boolean default true, tracking_url_pattern text not null, number_type text, fetch_mode text default 'BROWSER' check (fetch_mode in ('URLFETCH','BROWSER','MANUAL')), input_selector text, submit_selector text, result_selector text, status_regex text, eta_regex text, etd_regex text, vessel_regex text, voyage_regex text, location_regex text, event_regex text, captcha_keywords text, parser_mode text default 'REGEX', wait_strategy text default 'TIMEOUT' check (wait_strategy in ('TIMEOUT','NETWORK_IDLE','SELECTOR')), wait_seconds integer default 5, notes text, created_at timestamptz default now(), updated_at timestamptz default now());
create table tracking_jobs (id uuid primary key default gen_random_uuid(), shipment_id uuid references shipments(id) on delete cascade, carrier text not null, tracking_number text not null, tracking_number_type text, job_status text default 'PENDING' check (job_status in ('PENDING','RUNNING','COMPLETED','FAILED','MANUAL_REVIEW','CANCELLED')), attempts integer default 0, priority text default 'NORMAL', next_run_at timestamptz default now(), locked_at timestamptz, locked_by text, last_error text, created_at timestamptz default now(), updated_at timestamptz default now());
create table tracking_events (id uuid primary key default gen_random_uuid(), shipment_id uuid references shipments(id) on delete cascade, container_no text, event_date timestamptz, carrier text, tracking_number text, status text, eta date, etd date, vessel text, voyage text, location text, raw_event text, source text, confidence integer, created_at timestamptz default now());
create table manual_reviews (id uuid primary key default gen_random_uuid(), shipment_id uuid references shipments(id) on delete cascade, tracking_job_id uuid references tracking_jobs(id) on delete set null, carrier text, tracking_number text, reason text, carrier_url text, manual_text text, parsed_json jsonb, review_status text default 'PENDING' check (review_status in ('PENDING','APPROVED','REJECTED')), reviewed_by uuid references auth.users(id), created_at timestamptz default now(), updated_at timestamptz default now());
create table alerts (id uuid primary key default gen_random_uuid(), shipment_id uuid references shipments(id) on delete cascade, alert_type text not null, severity text default 'INFO' check (severity in ('INFO','WARNING','CRITICAL')), message text not null, status text default 'OPEN' check (status in ('OPEN','ACKNOWLEDGED','CLOSED')), sent_to text, created_at timestamptz default now(), updated_at timestamptz default now());
create table settings (key text primary key, value text, description text, updated_at timestamptz default now());
create index idx_shipments_direction on shipments(shipment_direction); create index idx_shipments_status on shipments(current_status); create index idx_shipments_eta on shipments(eta); create index idx_shipments_bl on shipments(bl_no); create index idx_shipments_booking on shipments(booking_no); create index idx_containers_no on containers(container_no); create index idx_tracking_jobs_status_next on tracking_jobs(job_status, next_run_at); create index idx_manual_reviews_status on manual_reviews(review_status); create index idx_tracking_events_shipment_date on tracking_events(shipment_id, event_date desc);
create or replace function set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end; $$;
do $$ declare t text; begin foreach t in array array['profiles','customers','suppliers','shipments','containers','shipment_milestones','documents','carrier_rules','tracking_jobs','manual_reviews','alerts','settings'] loop execute format('create trigger %I_set_updated_at before update on %I for each row execute function set_updated_at()', t, t); end loop; end $$;
